def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        score = 0.0
        penalty = 0.0
        decay = 1.0
        extra_penalties = 0.0
        bonus = 1.0
        oscillation = 0.0
        hysteresis = 0.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 7):
                penalty += (ratio ** (2 * k)) / (k ** 4 + 1)
            for j in range(1, 5):
                decay *= (1 - 1 / (ratio + j + 1))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            for l in range(1, 5):
                oscillation += np.sin(ratio / l) * np.exp(-l / ratio)
            priorities[i] = score * decay + oscillation
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x + 1)
                score += sign * (ratio ** x) / (x + 3)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio + 2))
            score = abs(score) * decay * 15
            for m in range(1, 4):
                bonus *= (1 + m / (ratio + 1))
            priorities[i] = score * bonus
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 6)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** p) / (p * 4)
            multiplier = 28 if ratio < 2.3 else 20 if ratio < 2.7 else 14
            score = abs(temp) * multiplier
            if ratio > 2.9:
                extra = 0
                for m in range(1, 8):
                    extra += (ratio ** m) / (m + 2)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for p in range(1, 18):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 6)
                else:
                    temp_score += (ratio ** p) / (p * 5)
            multiplier = 22 if ratio < 1.3 else 16 if ratio < 1.6 else 11
            score = abs(temp_score) * multiplier
            if ratio > 1.8:
                extra_penalty = 0
                for n in range(1, 9):
                    extra_penalty += (ratio ** n) / (n + 2)
                score += extra_penalty * 4
            for h in range(1, 4):
                hysteresis += np.cos(ratio * h) / (h + 1)
            priorities[i] = score + hysteresis
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 20):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 5)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 7)
                else:
                    temp_score += (ratio ** p) / (p * 4)
            if ratio < 0.15:
                multiplier = 35
                bonus = 1.2
            elif ratio < 0.35:
                multiplier = 26
                bonus = 1.1
            elif ratio < 0.55:
                multiplier = 19
                bonus = 1.0
            elif ratio < 0.75:
                multiplier = 11
                bonus = 0.9
            else:
                multiplier = 7
                bonus = 0.8
            score = abs(temp_score) * multiplier * bonus
            if ratio > 0.9:
                extra_penalties = 0
                for n in range(1, 10):
                    extra_penalties += (ratio ** n) / (n + 2)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 5):
                factor *= (1 + z / (bins[i] + 2))
            priorities[i] *= factor
        elif bins[i] <= 0:
            priorities[i] = np.inf
    return priorities
